import { cx } from '@/utils/cx';
import { ProgressMinimalIconsProps } from '../../application/progress-steps/progress-types';
import { NumberIcon } from './NumberIcon';

export const MinimalNumbers = ({
  items,
  text = false,
  size = 'sm',
  className,
  ...rest
}: ProgressMinimalIconsProps) => {
  const gaps = {
    sm: 'gap-3',
    md: 'gap-4',
  };

  const completed = items.filter((item) => item.status === 'complete').length;

  return (
    <div
      className={cx(
        'flex w-full flex-row items-center justify-center',
        gaps[size],
        className,
      )}
      {...rest}
    >
      {text && (
        <p className="text-sm font-medium text-secondary">
          Step {completed} of {items.length}
        </p>
      )}
      {items.map((item, index) => (
        <NumberIcon
          key={index}
          step={index + 1}
          item={item}
          size={size}
        />
      ))}
    </div>
  );
};
