import { cx } from '@/utils/cx';
import { ItemsType } from '../../application/progress-steps/progress-types';

interface NumberIconProps {
  step: number;
  size?: 'sm' | 'md';
  item: ItemsType<'number'>;
}

export const NumberIcon = ({ step, size = 'sm', item }: NumberIconProps) => {
  const statuses = {
    incomplete: {
      icon: 'bg-primary ring-1 ring-inset ring-secondary text-disabled',
    },
    current: {
      icon: 'bg-primary ring-1 ring-inset ring-secondary text-secondary',
    },
    complete: {
      icon: 'bg-success-solid text-fg-white',
    },
  };

  return (
    <span
      className={cx(
        'z-10 flex items-center justify-center rounded-full',
        statuses[item.status].icon,
        item.status === 'incomplete' && 'opacity-60',
        size === 'sm' ? 'size-6' : 'size-8',
      )}
    >
      {item.status === 'complete' ? (
        <svg
          width="12"
          height="12"
          viewBox="0 0 12 12"
          fill="none"
          className={cx(size === 'sm' ? 'size-3' : 'size-4')}
        >
          <path
            d="M10 3L4.5 8.5L2 6"
            stroke="white"
            strokeWidth="2"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </svg>
      ) : (
        <span
          className={cx('font-semibold', size === 'sm' ? 'text-xs' : 'text-sm')}
        >
          {step}
        </span>
      )}
    </span>
  );
};
