import { cloneElement } from 'react';
import { MinimalIconsVariant } from './ProgressSteps';
import { cx } from '@/index';

export const ProgressMinimalIconWrapper = ({
  children,
}: {
  children: React.ReactElement;
}) => {
  const { text, setText, items, className, size } =
    children.props as MinimalIconsVariant;
  const gaps = {
    sm: 'gap-3',
    md: 'gap-4',
  };

  if (text && setText) {
    const current = items.findIndex((item) => item.status === 'current') + 1;
    const total = items.length;

    return (
      <div
        className={cx(
          'flex w-full flex-row items-center justify-center',
          className,
          gaps[size || 'sm'],
        )}
      >
        <div className="w-fit">{setText(current, total)}</div>
        {cloneElement(children as React.ReactElement, {
          ...children.props,
          text: false,
          className: 'w-fit',
        })}
      </div>
    );
  }

  return children;
};
