import type {
  CommonProps,
  ProgressIconsCenteredProps,
  ProgressMinimalIconsProps,
  ComponentType,
} from '../../application/progress-steps/progress-types';
import { Progress } from '../../application/progress-steps/progress-steps';
import { MinimalNumbers } from './MinimalNumbers';
import { MinimalNumbersConnected } from './MinimalNumbersConnected';
import { ProgressMinimalIconWrapper } from './ProgressMinimalIconWrapper';

type IconsWithTextVariant = {
  variant: 'icons-with-text';
} & ProgressIconsCenteredProps<ComponentType>;

export type MinimalIconsVariant = {
  variant: 'minimal-icons';
  type: 'number' | 'icon';
  setText?: (current: number, total: number) => string;
} & ProgressMinimalIconsProps;

type MinimalIconsConnectedVariant = {
  variant: 'minimal-icons-connected';
  type: 'number' | 'icon';
} & CommonProps;

type TextWithLineVariant = {
  variant: 'text-with-line';
} & CommonProps;

export type ProgressStepsProps =
  | IconsWithTextVariant
  | MinimalIconsVariant
  | MinimalIconsConnectedVariant
  | TextWithLineVariant;

export const ProgressSteps = (props: ProgressStepsProps) => {
  switch (props.variant) {
    case 'icons-with-text':
      return <Progress.IconsWithText {...props} />;

    case 'minimal-icons':
      return props.type === 'number' ? (
        <ProgressMinimalIconWrapper>
          <MinimalNumbers {...props} />
        </ProgressMinimalIconWrapper>
      ) : (
        <ProgressMinimalIconWrapper>
          <Progress.MinimalIcons {...props} />
        </ProgressMinimalIconWrapper>
      );

    case 'minimal-icons-connected':
      return props.type === 'number' ? (
        <MinimalNumbersConnected {...props} />
      ) : (
        <Progress.MinimalIconsConnected
          {...props}
          orientation="horizontal"
        />
      );

    case 'text-with-line':
      return <Progress.TextWithLine {...props} />;
  }
};
